% entropy-driven adaptive procedureclearaxis('square')amin = -.2; amax = .2; na = 17;xmin = -1; xmax = 1; nx = 81;bmin = .5; bmax = 1.7; nb = 11;%bmin = log10(7); bmax = log10(7); db = 0.05;a = (amin:(amax-amin)/(na-1):(amax+0.0001));x = (xmin:(xmax-xmin)/(nx-1):(xmax+0.0001));b = bmin*(bmax/bmin).^(((1:nb)-1)/(nb-1));miss = 0.04;	% miss levelgamma = .5;		% 2AFC%gamma = 0;			% yes-no[tmp na] = size(a);[tmp nx] = size(x);[tmp nb] = size(b);a1 = kron(ones(1,nb), (1:na));b1 = kron((1:nb), ones(1,na));plot(x,gamma+(1-miss)*(1-gamma)*dprime(0,5,x),'-',0,.75,'o')%plot(x,weibull(1,log10(1.75),x),1,.5,'o')pause% 0				likelihood tablepr1ax = [];for ib=1:nb  for ia=1:na%    tmp = dprime(a(ia),b(ib),x);    pr1ax = [pr1ax; dprime(a(ia),b(ib),x)];  end  ibendpr1ax = gamma + (1-miss)*(1-gamma)*pr1ax;pr0ax = 1 - pr1ax;nexp = 1								% number of the experimentsntr = 2000								% number of the trials in experimentresa = zeros(nexp, ntr);resb = zeros(nexp, ntr);for k = 1:nexp							% experiment loop% 0										setting the prior  pab=ones([na*nb, 1])/(na*nb);  ta = amin+(amax-amin)*rand(1);		% all thresholds  ta = 0;%  tb = bmin+(bmax-bmin)*rand(1);		% all slopes  tb = 1;						% a particular slope  p = gamma + (1-gamma)*dprime(ta, tb, x); % actual psych. function  for n=1:ntr							% trial loop% 1		p(r|x)    pr0x = pab' * pr0ax;    pr1x = 1 - pr0x;% 2		p(a|x,r)    paxr0 = (pab*ones(size(x))) .* pr0ax+0.0000000001;    paxr0 = paxr0 ./ (ones(size(pab))*sum(paxr0));    paxr1 = (pab*ones(size(x))).*pr1ax+0.0000000001;    paxr1 = paxr1 ./ (ones(size(pab))*sum(paxr1));% 3		entropy    exr0 = -sum(paxr0 .* log(paxr0+0.0000000001));    exr1 = -sum(paxr1 .* log(paxr1+0.0000000001));% 4		expected entropy							    ex = pr0x .* exr0 + pr1x .* exr1;% 5		placing the new trial    [tmp inext] = min(ex);	e = -sum(pab.*log(pab));%	bit=1.4427*(e-ex(inext))    n	plot(ta, ex(1), 'o', x(inext), ex(1), '+', x, ex)	pause% 6		experimental trial	resp = 0.5*(sign(p(inext)-rand(1))+1)%    resp = input('Response: ');			% manual control% 7 updating p.d.f.    if resp == 1    % correct      pab = paxr1(:,inext);    else			% incorrect      pab = paxr0(:,inext);	end%	plot(pab)%	pause% 8 new estimate	ia = a1 * pab;					% predicted indices	ib = b1 * pab;    tta = (1-ia+floor(ia))*a(floor(ia))+(ia-floor(ia))*a(ceil(ia));			% predicted values    ttb = exp( (1-ib+floor(ib))*log(b(floor(ib)))+(ib-floor(ib))*log(b(ceil(ib))));% store errors (in dB units)    resa(k,n) = log10(tta/ta)*20;%	(tta-ta)*20    resb(k,n) = log10(ttb/tb)*20;  end % n%  if rem(k,100) == 0				% saving results%    k%    save ENTyn7 resa resb%  endend % kplot(1:ntr,mean(resa))				% plotting bias